     var predictions = splitModel.Transform(split.TestSet);
     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
 }
 else if (rowCount >= 10)
 {
     // Moderate dataset — use cross-validation for metrics
     Console.WriteLine($"Moderate dataset ({rowCount} rows). Using 2-fold cross-validation for metrics.");
     var cvResults = mlContext.BinaryClassification.CrossValidate(dataView, pipeline, numberOfFolds: 2, labelColumnName: "Label");
     var avgAcc = cvResults.Average(r => r.Metrics.Accuracy);
     var avgF1 = cvResults.Average(r => r.Metrics.F1Score);
     Console.WriteLine($"Cross-validated metrics — Accuracy: {avgAcc:F4}, F1: {avgF1:F4}");
 }
 else
 {
     Console.WriteLine($"Warning: Only {rowCount} rows — too few for reliable evaluation. Add more data for production use.");
 }

 // Train final model on all data, save, and register pooled prediction engine
 var model = pipeline.Fit(dataView);
 var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
 mlContext.Model.Save(model, dataView.Schema, modelPath);

 builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
     .FromFile(modelPath);

 var app = builder.Build();

 app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

 app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
 {
     var input = new CustomerData
     {
         Age = req.Age,
         Income = req.Income,
         Region = req.Region,
         PurchaseHistory = req.PurchaseHistory
     };
     var result = pool.Predict(input);
     return Results.Ok(new
     {
         willChurn = result.PredictedLabel,
         confidence = result.Probability
     });
 });

 app.Run();

